package webadmin

import "html/template"

var cleanLoginTemplate = template.Must(template.New("clean_login").Parse(`<!doctype html>
<html><head><meta charset="utf-8"><title>Robot Login</title><style>
body{font-family:system-ui,-apple-system,Segoe UI,Arial,sans-serif;background:#eef2f6;color:#17202a;margin:0;display:grid;place-items:center;min-height:100vh}
form{width:320px;background:#fff;border:1px solid #d7dee8;border-radius:8px;padding:22px;box-shadow:0 16px 45px rgba(15,23,42,.12)}
h1{font-size:18px;margin:0 0 16px}label{display:block;font-size:13px;color:#64748b;margin-bottom:6px}input{width:100%;box-sizing:border-box;height:36px;border:1px solid #b8c2d0;border-radius:6px;padding:0 10px;font:inherit}button{width:100%;height:36px;margin-top:14px;border:0;border-radius:6px;background:#2563eb;color:white;font:inherit;cursor:pointer}.err{margin-top:10px;color:#b91c1c;font-size:13px}
</style></head><body><form method="post" action="/login"><h1>Robot Web</h1><label>Password</label><input name="password" type="password" autofocus><button>Login</button>{{if .Error}}<div class="err">{{.Error}}</div>{{end}}</form></body></html>`))

var cleanIndexTemplate = template.Must(template.New("clean_index").Parse(`<!doctype html>
<html><head><meta charset="utf-8"><title>TW Robot Web</title><style>
:root{--bg:#eef2f6;--panel:#fff;--line:#d7dee8;--soft:#f8fafc;--text:#17202a;--muted:#64748b;--blue:#2563eb;--green:#15803d;--red:#b91c1c;--amber:#a16207}
*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font:14px system-ui,-apple-system,Segoe UI,Arial,sans-serif}header{height:48px;display:flex;align-items:center;gap:16px;padding:0 16px;background:#17202a;color:#fff}header b{font-size:16px}header span{opacity:.85}header a{margin-left:auto;color:#fff;text-decoration:none}.wrap{padding:12px 14px}.cards{display:grid;grid-template-columns:repeat(8,minmax(120px,1fr));gap:8px;margin-bottom:10px}.card,.scheduler,.panel{background:var(--panel);border:1px solid var(--line);border-radius:8px}.card{padding:9px 10px}.k{font-size:12px;color:var(--muted)}.v{font-size:18px;font-weight:700;margin-top:3px}.good .v{color:var(--green)}.bad .v{color:var(--red)}.toolbar{display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:10px}.toolbar .spacer{flex:1}button{height:32px;border:1px solid #b8c2d0;border-radius:6px;background:#fff;color:var(--text);padding:0 11px;font:inherit;cursor:pointer}button:hover{background:#f8fafc}button:disabled{opacity:.55;cursor:not-allowed}.primary{background:var(--blue);border-color:var(--blue);color:#fff}.primary:hover{background:var(--blue);border-color:var(--blue);color:#fff}.danger{border-color:#efb5b5;color:var(--red)}input,textarea{font:inherit;border:1px solid #b8c2d0;border-radius:6px;padding:7px;background:#fff}input[type=number]{width:92px}.scheduler{padding:10px;margin-bottom:10px}.schedgrid{display:grid;grid-template-columns:repeat(6,minmax(120px,1fr));gap:8px}.scheditem{border:1px solid #edf1f5;border-radius:6px;padding:7px 8px;background:#fbfdff}.schedreason{margin-top:8px;color:var(--muted);font-size:12px}.grid{display:grid;grid-template-rows:minmax(280px,1fr) 210px;gap:10px;height:calc(100vh - 150px)}.panel{overflow:hidden}.panelhead{height:36px;display:flex;align-items:center;gap:10px;padding:0 10px;background:var(--soft);border-bottom:1px solid var(--line)}.panelhead h3{margin:0;font-size:14px}.panelhead span{color:var(--muted);font-size:12px}.tablebox{height:calc(100% - 36px);overflow:auto}table{width:100%;border-collapse:collapse}th,td{padding:7px 8px;border-bottom:1px solid #edf1f5;text-align:center;white-space:nowrap}th{background:var(--soft);position:sticky;top:0;z-index:2;color:#475569;font-size:12px}tbody tr:nth-child(even){background:#fbfdff}tbody tr:hover{background:#eff6ff}tr.sel,.bulk-selected tr{background:#dbeafe!important}.pill{display:inline-block;padding:2px 7px;border-radius:999px;background:#e2e8f0;color:#334155;font-size:12px}.pill.ok{background:#dcfce7;color:#166534}.pill.warn{background:#fef3c7;color:#92400e}pre{margin:0;height:174px;overflow:auto;white-space:pre-wrap;background:#0f172a;color:#dbeafe;padding:10px;font:12px/1.45 Consolas,monospace}.toast{position:fixed;right:14px;bottom:14px;max-width:520px;background:#17202a;color:#fff;border-radius:7px;padding:10px 12px;box-shadow:0 12px 32px rgba(15,23,42,.22);display:none}dialog{border:1px solid var(--line);border-radius:8px;padding:0;min-width:460px;max-width:min(920px,96vw);box-shadow:0 18px 70px rgba(15,23,42,.22)}dialog::backdrop{background:rgba(15,23,42,.32)}.dlghead,.dlgfoot{display:flex;align-items:center;padding:12px 14px;background:var(--soft);border-bottom:1px solid var(--line)}.dlghead h3{margin:0;font-size:15px}.dlghead button{margin-left:auto}.dlgbody{padding:14px}.dlgfoot{justify-content:flex-end;gap:8px;border-top:1px solid var(--line);border-bottom:0}.formgrid{display:grid;grid-template-columns:160px 1fr;gap:10px 12px;align-items:center}.muted{color:var(--muted)}.configbox{width:min(860px,88vw);height:min(560px,70vh);font:12px/1.45 Consolas,monospace}@media(max-width:1250px){.cards{grid-template-columns:repeat(4,1fr)}}@media(max-width:900px){.cards,.schedgrid{grid-template-columns:repeat(2,1fr)}.grid{height:auto;grid-template-rows:420px 220px}}
</style></head><body>
<header><b>TW Robot Web</b><span>Web {{.WebAddr}}</span><span>TCP {{.RobotAddr}}</span><span id="gameHead">Game: -</span><a href="/logout">Logout</a></header>
<div class="wrap">
<div class="cards"><div class="card" id="mRobot"><div class="k">Robot</div><div class="v">-</div></div><div class="card" id="mGame"><div class="k">Game port</div><div class="v">-</div></div><div class="card" id="mHook"><div class="k">Game Hook</div><div class="v">-</div></div><div class="card" id="mDB"><div class="k">Database</div><div class="v">-</div></div><div class="card" id="mKey"><div class="k">Key</div><div class="v">-</div></div><div class="card"><div class="k">Auto</div><div class="v" id="mAuto">-</div></div><div class="card" id="mOnlineCard"><div class="k" id="mOnlineLabel">Online / Target</div><div class="v" id="mOnline">-</div></div><div class="card"><div class="k">Store</div><div class="v" id="mStore">-</div></div></div>
<div class="toolbar"><button class="primary" onclick="refreshAll()">Refresh</button><button data-key-action="1" onclick="openAutoDialog()">Auto</button><button data-key-action="1" onclick="openOnlineDialog()">Online</button><button data-key-action="1" onclick="runAction('robotsMove')">Move</button><button data-key-action="1" onclick="runAction('robotsShout')">Shout</button><button data-key-action="1" onclick="runAction('robotsStoreAsync')">Store</button><button data-key-action="1" onclick="runAction('robotsLogoutAsync')">Logout</button><button data-key-action="1" class="danger" onclick="openCleanupDialog()">Cleanup</button><button id="keyButton" onclick="openKeyDialog()">Key</button><span class="spacer"></span><label><select id="autoRefreshInterval" onchange="toggleAutoRefresh()"><option value="3000">3s</option><option value="5000">5s</option><option value="8000" selected>8s</option><option value="off">Off</option></select> Auto refresh</label><label>Count <input id="actionCount" type="number" min="1" max="1000" value="1"></label><span class="muted" id="selectedInfo">Selected 0</span></div>
<div class="scheduler"><div class="schedgrid"><div class="scheditem"><div class="k">Policy mode</div><div class="v" id="sMode">-</div></div><div class="scheditem"><div class="k">Attach pace</div><div class="v" id="sOnline">-</div></div><div class="scheditem"><div class="k">Store policy</div><div class="v" id="sStore">-</div></div><div class="scheditem"><div class="k">Scale window</div><div class="v" id="sScale">-</div></div><div class="scheditem"><div class="k">Pressure guard</div><div class="v" id="sPressure">-</div></div><div class="scheditem"><div class="k">Release guard</div><div class="v" id="sRelease">-</div></div></div><div class="schedreason" id="sReason">-</div></div>
<div class="grid"><div class="panel"><div class="panelhead"><h3>Robots</h3><span id="listInfo">-</span></div><div class="tablebox"><table id="tbl"><thead><tr><th><input type="checkbox" id="checkAll" onchange="toggleAll(this.checked)"></th><th>UID</th><th>CID</th><th>Name</th><th>Actor</th><th>State</th><th>Level</th><th>Job/Grow</th><th>Village</th><th>Area</th><th>X</th><th>Y</th><th>Uptime</th><th>Store</th></tr></thead><tbody></tbody></table></div></div><div class="panel"><div class="panelhead"><h3>Log</h3><span id="logInfo">/root/config/log_robot</span></div><pre id="log"></pre></div></div></div>
<dialog id="modal"><div class="dlghead"><h3 id="modalTitle"></h3><button onclick="closeModal()">Close</button></div><div class="dlgbody" id="modalBody"></div><div class="dlgfoot" id="modalFoot"></div></dialog><div class="toast" id="toast"></div>
<script>
const selected=new Set();let currentRows=[],busy=false,keyBlocked=false,dbBlocked=false,gameBlocked=false,autoRefreshTimer=null,gameMaxUser=0;
function byId(id){return document.getElementById(id)}function text(v){return String(v??'')}function escapeHTML(v){return text(v).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function toast(msg){const t=byId('toast');t.textContent=msg;t.style.display='block';clearTimeout(t._timer);t._timer=setTimeout(()=>t.style.display='none',3600)}
function actionName(cmd){return ({robotsOnlineAsync:'Online',robotsStoreAsync:'Store',robotsLogoutAsync:'Logout',cleanupRobotsAsync:'Cleanup',robotsMove:'Move',robotsShout:'Shout'}[cmd]||cmd)}
function setBusy(v){busy=v;document.querySelectorAll('button').forEach(b=>b.disabled=v);applyKeyGate()}function applyKeyGate(){const blocked=keyBlocked||dbBlocked||gameBlocked;document.querySelectorAll('[data-key-action="1"]').forEach(b=>b.disabled=busy||blocked);const kb=byId('keyButton');if(kb)kb.disabled=busy}
async function api(command,payload={}){const r=await fetch('/api/call',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({command,payload})});const x=await r.json().catch(()=>({ok:false,error:'invalid json'}));if(!r.ok||!x.ok)throw new Error(x.error||('HTTP '+r.status));return x}
function resultOf(x){return x&&x.result&&x.result.result?x.result.result:x.result}function writeLog(v){byId('log').textContent=typeof v==='string'?v:JSON.stringify(v,null,2)}
async function guarded(name,fn){if(busy)return;setBusy(true);try{const out=await fn();if(out!==undefined)writeLog(out);toast(name+' ok')}catch(e){writeLog({ok:false,error:e.message});toast(name+' failed: '+e.message)}finally{setBusy(false)}}
async function refreshAll(){await guarded('Refresh',async()=>{await Promise.all([refreshStatus(),refreshScheduler(),refreshRobots(),checkGame(),checkGameHook(),refreshDatabase(),refreshKeypair()]);return 'refreshed '+new Date().toLocaleTimeString()})}
async function refreshQuiet(){if(busy||byId('autoRefreshInterval')?.value==='off')return;try{await Promise.all([refreshStatus(),refreshScheduler(),refreshRobots(),checkGame(),checkGameHook(),refreshDatabase(),refreshKeypair()])}catch(e){}}
async function refreshStatus(){const x=await api('autoStatus');const r=resultOf(x)||{};byId('mAuto').textContent=r.enabled?'On':'Off';byId('mOnline').textContent=(r.running||0)+' / '+(r.target_online||0);byId('mOnlineLabel').textContent=gameMaxUser?'Online / Max '+gameMaxUser:'Online / Target';byId('mStore').textContent=String(r.store_running||0);const sx=await api('systemStatus');const s=resultOf(sx)||{};const el=byId('mRobot');el.className='card good';el.querySelector('.v').textContent=Number(s.robot_cpu_percent||0).toFixed(1)+'% '+(s.robot_memory_mb||0)+'MB';el.querySelector('.k').textContent='Robot / '+(s.robot_threads||0)+' goroutines'}
async function refreshScheduler(){try{const x=await api('schedulerStatus');const s=resultOf(x)||{};byId('sMode').textContent=s.mode||'-';byId('sOnline').textContent=(s.online_start_rate||0)+'/s batch '+(s.online_batch_size||0);byId('sStore').textContent=(s.store_running||0)+'/'+(s.store_concurrent||0)+' p'+(s.store_probability_percent||0)+'%';byId('sScale').textContent='up '+(s.scale_up_batch||0)+' down '+(s.scale_down_batch||0);byId('sPressure').textContent='login '+(s.connecting||0)+' cpu '+Number(s.cpu_percent||0).toFixed(1)+'%';byId('sRelease').textContent='br '+(s.breaker_release_batch||0)+' port '+(s.port_down_release_batch||0);const op=s.recent_operation?(' | op '+s.recent_operation+' '+(s.recent_operation_state||'')+(s.recent_operation_summary?' '+s.recent_operation_summary:'')):'';byId('sReason').textContent=(s.reason||'-')+' | running '+(s.running||0)+'/'+(s.target_online||0)+' idle '+(s.idle||0)+' port '+(s.game_port_ready?'ready':'down')+' breaker '+(s.breaker_active?'on':'off')+' | actor i/a/o/r/b/rel '+(s.actor_idle||0)+'/'+(s.actor_assigned||0)+'/'+(s.actor_online||0)+'/'+(s.actor_running||0)+'/'+(s.actor_busy||0)+'/'+(s.actor_releasing||0)+op}catch(e){byId('sMode').textContent='error';byId('sReason').textContent=e.message}}
function uptime(sec){sec=Number(sec||0);const h=Math.floor(sec/3600),m=Math.floor((sec%3600)/60),s=sec%60;return h?h+':'+String(m).padStart(2,'0')+':'+String(s).padStart(2,'0'):m+':'+String(s).padStart(2,'0')}
async function refreshRobots(){const x=await api('robotsStatus',{count:10000});const r=resultOf(x)||{};currentRows=r.robots||[];const tb=document.querySelector('#tbl tbody');tb.textContent='';tb.classList.remove('bulk-selected');for(const a of currentRows){const uid=String(a.uid||'');const tr=document.createElement('tr');if(selected.has(uid))tr.className='sel';const cb=document.createElement('input');cb.type='checkbox';cb.checked=selected.has(uid);appendCell(tr,cb);appendCell(tr,uid);appendCell(tr,text(a.cid));appendCell(tr,text(a.name));const actor=document.createElement('span');const deleting=a.operation==='cleanup';actor.className='pill '+(deleting?'warn':(a.actor_attached?'ok':''));actor.textContent=deleting?'deleting':(a.actor_attached?('slot '+(a.actor_slot||'-')+' '+(a.actor_state||'')):'free');actor.title=deleting?'cleanup running':(a.actor_busy?('busy '+(a.actor_busy_kind||'')):'');appendCell(tr,actor);const state=document.createElement('span');state.className='pill '+(a.health_state==='ok'?'ok':(a.health_state==='suspect'?'warn':'bad'));state.textContent=(a.runtime_state||a.state_name||'-')+' -> '+(a.desired_state||'-');state.title='db '+(a.db_state||'-')+' health '+(a.health_state||'-')+(a.operation?' op '+a.operation:'');appendCell(tr,state);[a.level,text(a.job)+'/'+text(a.grow),a.village,a.area,a.x,a.y,uptime(a.uptime_seconds)].forEach(v=>appendCell(tr,text(v)));const store=a.store_display_ack?'active':((a.store_created||a.robot_type==2||a.robot_type==3)?'pending':'');const span=document.createElement('span');if(store){span.className='pill '+(store==='active'?'ok':'warn');span.textContent=store}appendCell(tr,span);tr.onclick=e=>{tb.classList.remove('bulk-selected');if(e.target.tagName!=='INPUT')cb.checked=!cb.checked;cb.checked?selected.add(uid):selected.delete(uid);tr.className=selected.has(uid)?'sel':'';updateSelectedInfo()};tb.appendChild(tr)}byId('listInfo').textContent=currentRows.length+' robots, '+new Date().toLocaleTimeString();updateSelectedInfo()}
function appendCell(tr,v){const td=document.createElement('td');if(v instanceof Node)td.appendChild(v);else td.textContent=v;tr.appendChild(td)}function selectedPayload(){const u=[...selected].map(Number);return u.length?{uids:u}:{count:Math.max(1,Number(byId('actionCount').value||1))}}function updateSelectedInfo(){byId('selectedInfo').textContent='Selected '+selected.size;byId('checkAll').checked=currentRows.length>0&&currentRows.every(r=>selected.has(String(r.uid||'')))}
async function checkGame(){const x=await fetch('/api/game-port').then(r=>r.json());gameBlocked=!x.ok;gameMaxUser=Number(x.max_user_num||0);byId('mOnlineLabel').textContent=gameMaxUser?'Online / Max '+gameMaxUser:'Online / Target';byId('gameHead').textContent='Game: '+(x.ok?'open':'closed')+' '+(x.addr||'');const el=byId('mGame');el.className='card '+(x.ok?'good':'bad');el.querySelector('.v').textContent=x.ok?'Open':'Closed';el.title=(x.error||x.addr||'')+(gameMaxUser?' max '+gameMaxUser:'');applyKeyGate()}
async function checkGameHook(){try{const x=await fetch('/api/game-hook').then(r=>r.json());const el=byId('mHook');const total=Number(x.total||0),loaded=Number(x.loaded||0);let label='Error',cls='bad';if(x.state==='loaded'){label='Loaded';cls='good'}else if(x.state==='partial'){label='Partial '+loaded+'/'+total;cls='bad'}else if(x.state==='missing'){label='Missing';cls='bad'}else if(x.state==='no_process'){label='No Process';cls='bad'}el.className='card '+cls;el.querySelector('.v').textContent=label;el.title=(x.library||'')+' loaded '+loaded+'/'+total+' '+(x.error||'')}catch(e){const el=byId('mHook');el.className='card bad';el.querySelector('.v').textContent='Error';el.title=e.message}}
async function refreshDatabase(){try{const x=await api('databaseStatus');const r=resultOf(x)||{};dbBlocked=!r.ok;const el=byId('mDB');el.className='card '+(dbBlocked?'bad':'good');el.querySelector('.v').textContent=r.ok?'OK '+(r.latency_ms||0)+'ms':'Error';el.title=r.ok?(r.target||''):(r.error||'database unavailable');applyKeyGate()}catch(e){dbBlocked=true;applyKeyGate();const el=byId('mDB');el.className='card bad';el.querySelector('.v').textContent='Error';el.title=e.message}}
async function refreshKeypair(){try{const x=await api('keypairStatus');const r=resultOf(x)||{};keyBlocked=!(r.key_state==='default'||r.key_state==='user'||r.game_valid);const el=byId('mKey');el.className='card '+(keyBlocked?'bad':'good');el.querySelector('.v').textContent=r.key_state_label||r.key_state||'-';applyKeyGate()}catch(e){keyBlocked=true;applyKeyGate();const el=byId('mKey');el.className='card bad';el.querySelector('.v').textContent='Error'}}
async function runAction(cmd){await guarded(actionName(cmd),async()=>{const x=await api(cmd,selectedPayload());setTimeout(refreshAll,1000);return x})}
function toggleAll(checked){const tb=document.querySelector('#tbl tbody');tb.classList.remove('bulk-selected');if(checked){currentRows.forEach(r=>selected.add(String(r.uid||'')))}else{selected.clear()}document.querySelectorAll('#tbl tbody tr').forEach(tr=>{const uid=tr.children[1]?tr.children[1].textContent:'';const on=selected.has(uid);tr.className=on?'sel':'';const cb=tr.querySelector('input[type=checkbox]');if(cb)cb.checked=on});updateSelectedInfo()}
function closeModal(){byId('modal').close()}function showModal(title,body,foot){byId('modalTitle').textContent=title;byId('modalBody').innerHTML=body;byId('modalFoot').innerHTML=foot||'<button onclick="closeModal()">Close</button>';byId('modal').showModal()}
function openOnlineDialog(){if(selected.size){runAction('robotsOnlineAsync');return}showModal('Online','<div class="formgrid"><label>Count</label><input id="onlineCount" type="number" min="1" max="1000" value="10"></div>','<button onclick="closeModal()">Cancel</button><button class="primary" onclick="submitOnline()">Online</button>')}async function submitOnline(){const c=Math.max(1,Number(byId('onlineCount').value||1));closeModal();await guarded('Online',async()=>api('robotsOnlineAsync',{count:c}))}
function openCleanupDialog(){const target=selected.size?selected.size+' selected robots':'all robot registry candidates';showModal('Cleanup','<p>Cleanup deletes robot registry/database rows for '+escapeHTML(target)+'. Normal shrink/logout should not use cleanup.</p>','<button onclick="closeModal()">Cancel</button><button class="danger" onclick="submitCleanup()">Cleanup</button>')}async function submitCleanup(){const p=selected.size?{uids:[...selected].map(Number),force:true}:{force:true};closeModal();await guarded('Cleanup',async()=>api('cleanupRobotsAsync',p))}
async function openAutoDialog(){await guarded('Read auto config',async()=>{const x=await api('robotConfigGet');const cfg=(resultOf(x)||{}).config||{};showModal('Auto','<div class="formgrid"><label>Enabled</label><label><input id="autoEnabled" type="checkbox" '+(String(cfg.auto_actions)==='true'?'checked':'')+'> On</label><label>Target online</label><input id="autoTarget" type="number" min="1" max="1000" value="'+escapeHTML(cfg.auto_target_online_count||20)+'"><label>Debug fixed spawn</label><label><input id="spawnFixed" type="checkbox" '+(String(cfg.spawn_fixed)==='true'?'checked':'')+'> fixed town / birth point</label><label>Town</label><input id="spawnVillage" type="number" min="1" max="3" value="'+escapeHTML(cfg.spawn_village||3)+'"><label>Birth area</label><input id="spawnArea" type="number" min="0" max="999" value="'+escapeHTML(cfg.spawn_area||0)+'"><div class="muted" style="grid-column:1/-1">Strategy derives login pace, actor scaling, store probability, breaker and release behavior automatically.</div></div>','<button onclick="closeModal()">Cancel</button><button onclick="submitAuto(false)">Save and pause</button><button class="primary" onclick="submitAuto(true)">Save and start</button>')})}
async function submitAuto(forceStart){const enabled=forceStart||byId('autoEnabled').checked;const updates={'auto.auto_target_online_count':String(byId('autoTarget').value||20),'auto.auto_actions':String(enabled),'spawn.spawn_fixed':String(byId('spawnFixed').checked),'spawn.spawn_village':String(byId('spawnVillage').value||3),'spawn.spawn_area':String(byId('spawnArea').value||0)};closeModal();await guarded('Auto',async()=>{const config=await api('robotConfigUpdate',{updates});const auto=await api(enabled?'autoStart':'autoStop');setTimeout(refreshAll,1000);return {config,auto}})}
async function openKeyDialog(){await guarded('Key',async()=>{const x=await api('keypairStatus');showModal('RSA Key','<pre>'+escapeHTML(JSON.stringify(resultOf(x)||{},null,2))+'</pre>','<button onclick="closeModal()">Close</button><button onclick="downloadCurrentKeypair()">Download</button><button class="primary" onclick="releaseDefaultKeypair()">Release default</button>')})}async function releaseDefaultKeypair(){closeModal();await guarded('Release key',async()=>api('keypairReleaseDefault',{}))}function downloadCurrentKeypair(){window.location='/api/keypair-download'}
function toggleAutoRefresh(){if(autoRefreshTimer){clearInterval(autoRefreshTimer);autoRefreshTimer=null}const v=byId('autoRefreshInterval')?.value;if(v&&v!=='off')autoRefreshTimer=setInterval(refreshQuiet,Number(v))}
refreshAll();toggleAutoRefresh();
</script></body></html>`))
